import { useEffect, useState } from "react";
import Link from "next/link";

type Item = {
  decision_id: string;
  decision_title: string;
  regulator_code: string;
  proposition: {
    id: string;
    prop_type: string;
    epistemic_class: string;
    claim_text: string;
    confidence: number;
    evidence: Array<{ page_no: number; quote: string }>;
  };
};

export default function ReviewPage() {
  const [items, setItems] = useState<Item[]>([]);
  const [message, setMessage] = useState<string | null>(null);

  async function refresh() {
    const res = await fetch("/api/review");
    const data = await res.json();
    setItems(data.items || []);
  }

  useEffect(() => {
    refresh();
  }, []);

  async function act(item: Item, review_status: "accepted" | "rejected") {
    setMessage(null);
    const res = await fetch("/api/review", {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        decision_id: item.decision_id,
        proposition_id: item.proposition.id,
        review_status,
      }),
    });
    const data = await res.json();
    if (!res.ok) {
      setMessage(data.error || "Review failed");
      return;
    }
    setMessage(`${review_status}: ${item.proposition.prop_type}`);
    await refresh();
  }

  return (
    <section className="panel">
      <h1>Review queue</h1>
      <p>
        No proposition is published without supporting source spans and an
        accept/edit decision.
      </p>
      {message && <p className="warning">{message}</p>}
      {items.length === 0 && <p>Queue empty.</p>}
      <div className="prop-list">
        {items.map((item) => (
          <div className="prop" key={item.proposition.id}>
            <div className="prop-type">
              {item.regulator_code} · {item.proposition.prop_type} ·{" "}
              {item.proposition.epistemic_class}
            </div>
            <p className="claim">{item.proposition.claim_text}</p>
            <p>
              <Link href={`/decisions/${item.decision_id}`}>
                {item.decision_title}
              </Link>
            </p>
            <ul>
              {item.proposition.evidence.map((ev, i) => (
                <li key={i}>
                  page {ev.page_no}: “{ev.quote}”
                </li>
              ))}
            </ul>
            <button type="button" onClick={() => act(item, "accepted")}>
              Accept & publish
            </button>{" "}
            <button type="button" onClick={() => act(item, "rejected")}>
              Reject
            </button>
          </div>
        ))}
      </div>
    </section>
  );
}"use client";

import { FormEvent, useState } from "react";
import Link from "next/link";

type Hit = {
  decision_id: string;
  title: string;
  regulator_code: string;
  profession?: string;
  prop_type?: string;
  claim_text?: string;
  page_no?: number | null;
  score: number;
};

export default function SearchPage() {
  const [q, setQ] = useState("misconduct");
  const [regulator, setRegulator] = useState("");
  const [hits, setHits] = useState<Hit[]>([]);
  const [notice, setNotice] = useState("");

  async function onSubmit(e: FormEvent) {
    e.preventDefault();
    const params = new URLSearchParams({ q });
    if (regulator) params.set("regulator", regulator);
    const res = await fetch(`/api/search?${params.toString()}`);
    const data = await res.json();
    setHits(data.hits || []);
    setNotice(data.notice || "");
  }

  return (
    <section className="panel">
      <h1>Search</h1>
      <p>Keyword full-text search over published propositions only.</p>
      <form onSubmit={onSubmit} style={{ display: "grid", gap: "0.75rem", maxWidth: 640 }}>
        <input
          value={q}
          onChange={(e) => setQ(e.target.value)}
          placeholder="Keywords"
          style={{ padding: "0.55rem" }}
        />
        <select value={regulator} onChange={(e) => setRegulator(e.target.value)}>
          <option value="">All regulators</option>
          <option value="MCHK">MCHK</option>
          <option value="DCHK">DCHK</option>
        </select>
        <button type="submit">Search</button>
      </form>
      {notice && <p className="warning">{notice}</p>}
      <div className="prop-list" style={{ marginTop: "1rem" }}>
        {hits.map((hit, idx) => (
          <div className="prop" key={`${hit.decision_id}-${idx}`}>
            <div className="prop-type">
              {hit.regulator_code}
              {hit.prop_type ? ` · ${hit.prop_type}` : ""}
              {hit.page_no ? ` · page ${hit.page_no}` : ""}
            </div>
            <p className="claim">{hit.claim_text || hit.title}</p>
            <Link
              href={`/decisions/${hit.decision_id}${hit.page_no ? `#page-${hit.page_no}` : ""}`}
            >
              Open decision
            </Link>
          </div>
        ))}
      </div>
    </section>
  );
}"use client";

