}/**
 * Shared RegLens HK contracts (Milestone 2A).
 * Keep in sync with packages/contracts/contracts.v1.json and Python enums.
 */

export const REGULATOR_CODES = ["MCHK", "DCHK"] as const;
export type RegulatorCode = (typeof REGULATOR_CODES)[number];

export const PROFESSIONS = ["doctor", "dentist"] as const;
export type Profession = (typeof PROFESSIONS)[number];

export const PROP_TYPES = [
  "charge",
  "rule",
  "finding",
  "legal_test",
  "aggravating_factor",
  "mitigating_factor",
  "sanction",
  "costs",
  "authority",
  "appeal_status",
] as const;
export type PropType = (typeof PROP_TYPES)[number];

export const EPISTEMIC_CLASSES = ["fact", "interpretation"] as const;
export type EpistemicClass = (typeof EPISTEMIC_CLASSES)[number];

export const REVIEW_STATUSES = [
  "pending",
  "accepted",
  "edited",
  "rejected",
] as const;
export type ReviewStatus = (typeof REVIEW_STATUSES)[number];

export type EvidenceRef = {
  span_id: string | null;
  page_no: number;
  quote: string;
  char_start?: number | null;
  char_end?: number | null;
};

export type Proposition = {
  id: string;
  prop_type: PropType;
  epistemic_class: EpistemicClass;
  claim_text: string;
  confidence: number;
  review_status: ReviewStatus;
  published: boolean;
  evidence: EvidenceRef[];
};

export type DecisionPage = {
  span_id: string;
  page_no: number;
  text: string;
};

export type DecisionRecord = {
  id: string;
  document_id: string;
  document_sha256: string;
  regulator_code: RegulatorCode;
  source_id: string;
  title: string;
  case_ref?: string | null;
  decision_date?: string | null;
  profession?: Profession | null;
  defendant_name_as_published?: string | null;
  defendant_registration_no?: string | null;
  source_url?: string | null;
  licence_notice?: string;
  coverage?: { missing_fields?: string[]; warnings?: string[] };
  text_quality?: string;
  extractor?: Record<string, string>;
  pages: DecisionPage[];
  propositions: Proposition[];
  generated_at?: string;
};

/** Publication is allowed only for reviewed propositions with evidence. */
export function canPublishProposition(p: {
  review_status: ReviewStatus;
  evidence: EvidenceRef[];
}): boolean {
  if (p.review_status !== "accepted" && p.review_status !== "edited") {
    return false;
  }
  return Array.isArray(p.evidence) && p.evidence.length > 0;
}-- RegLens HK Milestone 1 schema
-- PostgreSQL 16+ with pgvector

CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE EXTENSION IF NOT EXISTS "vector";

CREATE TABLE regulators (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    code            TEXT NOT NULL UNIQUE,
    name            TEXT NOT NULL,
    homepage_url    TEXT,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE sources (
    id                  UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    regulator_id        UUID NOT NULL REFERENCES regulators(id),
    source_id           TEXT NOT NULL UNIQUE,
    index_url           TEXT,
    licence_status      TEXT NOT NULL DEFAULT 'internal_use_only',
    terms_reviewed_at   TIMESTAMPTZ,
    notes               TEXT,
    created_at          TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE documents (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    source_id       UUID NOT NULL REFERENCES sources(id),
    external_ref    TEXT,
    title           TEXT,
    decision_date   DATE,
    hearing_dates   DATE[],
    language        TEXT NOT NULL DEFAULT 'en',
    mime_type       TEXT NOT NULL,
    byte_size       BIGINT NOT NULL,
    sha256          TEXT NOT NULL,
    storage_key     TEXT NOT NULL,
    ingest_status   TEXT NOT NULL DEFAULT 'stored',
    text_quality    TEXT,
    ocr_used        BOOLEAN NOT NULL DEFAULT FALSE,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT now(),
    immutable       BOOLEAN NOT NULL DEFAULT TRUE,
    CONSTRAINT documents_sha256_hex CHECK (sha256 ~ '^[a-f0-9]{64}$'),
    CONSTRAINT documents_sha256_unique UNIQUE (sha256)
);

CREATE UNIQUE INDEX documents_storage_key_uidx ON documents (storage_key);

CREATE TABLE document_versions (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    document_id     UUID NOT NULL REFERENCES documents(id),
    sha256          TEXT NOT NULL,
    storage_key     TEXT NOT NULL,
    acquired_at     TIMESTAMPTZ NOT NULL DEFAULT now(),
    note            TEXT
);

CREATE TABLE document_spans (
    id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    document_id     UUID NOT NULL REFERENCES documents(id) ON DELETE CASCADE,
    page_no         INTEGER NOT NULL CHECK (page_no >= 1),
    span_type       TEXT NOT NULL DEFAULT 'page'
                    CHECK (span_type IN ('page', 'block', 'paragraph')),
    char_start      INTEGER,
    char_end        INTEGER,
    text            TEXT NOT NULL,
    text_hash       TEXT NOT NULL,
    bbox_json       JSONB,
    created_at      TIMESTAMPTZ NOT NULL DEFAULT now(),
    UNIQUE (document_id, page_no, span_type, text_hash)
);

CREATE TABLE practitioners (
    id                  UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    regulator_id        UUID NOT NULL REFERENCES regulators(id),
    registration_no     TEXT,
    display_name        TEXT NOT NULL,
    profession          TEXT NOT NULL CHECK (profession IN ('doctor', 'dentist')),
    normalized_name     TEXT NOT NULL,
    UNIQUE (regulator_id, registration_no)
);

CREATE TABLE decisions (
    id                      UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    document_id             UUID NOT NULL UNIQUE REFERENCES documents(id),
    regulator_id            UUID NOT NULL REFERENCES regulators(id),
    case_ref                TEXT,
    decision_date           DATE,
    profession              TEXT CHECK (profession IN ('doctor', 'dentist')),
    appeal_status_as_stated TEXT,
    published_at            TIMESTAMPTZ,
    coverage_json           JSONB NOT NULL DEFAULT '{}'::jsonb,
    created_at              TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE decision_practitioners (
    decision_id     UUID NOT NULL REFERENCES decisions(id) ON DELETE CASCADE,
    practitioner_id UUID NOT NULL REFERENCES practitioners(id),
    role            TEXT NOT NULL DEFAULT 'defendant',
    PRIMARY KEY (decision_id, practitioner_id, role)
);

CREATE TABLE extraction_runs (
    id                  UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    document_id         UUID NOT NULL REFERENCES documents(id),
    pipeline_version    TEXT NOT NULL,
    model_provider      TEXT NOT NULL,
    model_version       TEXT NOT NULL,
    prompt_version      TEXT NOT NULL,
    started_at          TIMESTAMPTZ NOT NULL DEFAULT now(),
    finished_at         TIMESTAMPTZ,
    status              TEXT NOT NULL DEFAULT 'running',
    input_hash          TEXT NOT NULL,
    UNIQUE (document_id, input_hash)
);

CREATE TABLE propositions (
    id                  UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    decision_id         UUID NOT NULL REFERENCES decisions(id) ON DELETE CASCADE,
    extraction_run_id   UUID NOT NULL REFERENCES extraction_runs(id),
    prop_type           TEXT NOT NULL,
    epistemic_class     TEXT NOT NULL CHECK (epistemic_class IN ('fact', 'interpretation')),
    claim_text          TEXT NOT NULL,
    structured_json     JSONB,
    confidence          DOUBLE PRECISION NOT NULL CHECK (confidence >= 0 AND confidence <= 1),
    review_status       TEXT NOT NULL DEFAULT 'pending'
