    reviewed_by         TEXT,
    reviewed_at         TIMESTAMPTZ,
    published           BOOLEAN NOT NULL DEFAULT FALSE
);

CREATE TABLE proposition_spans (
    proposition_id  UUID NOT NULL REFERENCES propositions(id) ON DELETE CASCADE,
