                "claim_text": "A legal test claim",
                "confidence": 0.4,
                "evidence": [{"page_no": 1, "quote": "A legal test claim"}],
            }
        ],
    }
    errors = validate_extraction(payload)
    assert errors, "legal_test labelled as fact should fail schema"MIT License

