  border: 1px solid var(--line);
  padding: 1.25rem 1.4rem;
}

.meta-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 0.75rem 1.25rem;
  margin: 1rem 0 1.5rem;
}

.meta-grid dt {
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--muted);
}

.meta-grid dd {
  margin: 0.15rem 0 0;
  font-family: var(--sans);
}

.warning {
  border-left: 4px solid var(--warn);
  padding: 0.75rem 1rem;
  margin: 1rem 0 1.5rem;
  background: rgba(138, 75, 8, 0.08);
}

.prop-list {
  display: grid;
  gap: 1rem;
}

.prop {
  padding: 1rem 0;
  border-top: 1px solid var(--line);
}

.prop-type {
  font-family: var(--mono);
  font-size: 0.8rem;
  color: var(--accent);
}

.claim {
  font-family: var(--sans);
  font-size: 1.15rem;
  margin: 0.35rem 0 0.6rem;
}

.evidence a {
  font-family: var(--mono);
  font-size: 0.85rem;
}

.page-block {
  margin: 1.5rem 0;
  padding: 1rem;
  background: rgba(20, 32, 51, 0.03);
  border: 1px solid var(--line);
  scroll-margin-top: 1.5rem;
}

.page-block.highlight {
  outline: 2px solid var(--accent);
  background: rgba(15, 107, 92, 0.08);
}

.page-block pre {
  white-space: pre-wrap;
  font-family: var(--mono);
  font-size: 0.85rem;
  line-height: 1.45;
  margin: 0.5rem 0 0;
}

.badge {
  display: inline-block;
  font-size: 0.75rem;
  border: 1px solid var(--line);
  padding: 0.15rem 0.45rem;
  margin-right: 0.35rem;
  color: var(--muted);
}

.nav {
  display: flex;
  flex-wrap: wrap;
  gap: 0.85rem;
  align-items: center;
  margin-top: 1rem;
}

.nav a,
.nav button {
  font-family: var(--ui);
  color: var(--accent);
  background: transparent;
  border: 1px solid var(--line);
  padding: 0.35rem 0.7rem;
  cursor: pointer;
  text-decoration: none;
}

.evidence-mark {
  background: rgba(15, 107, 92, 0.22);
  color: inherit;
  padding: 0 0.1em;
