import { useEffect } from "react";
import type { DecisionRecord } from "../lib/data";

function highlightQuote(text: string, quote: string): string {
  if (!quote) return escapeHtml(text);
  const idx = text.indexOf(quote);
  if (idx < 0) return escapeHtml(text);
  return (
    escapeHtml(text.slice(0, idx)) +
    '<mark class="evidence-mark">' +
    escapeHtml(quote) +
    "</mark>" +
    escapeHtml(text.slice(idx + quote.length))
  );
}

function escapeHtml(s: string): string {
  return s
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;");
}

export function DecisionView({ decision }: { decision: DecisionRecord }) {
  useEffect(() => {
    const hash = window.location.hash.replace("#", "");
    if (!hash) return;
    const el = document.getElementById(hash);
    if (el) {
      el.classList.add("highlight");
      el.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  }, []);

  const published = decision.propositions.filter((p) => p.published);
  const unpublished = decision.propositions.filter((p) => !p.published);
  const quotesByPage = new Map<number, string[]>();
  for (const prop of published) {
    for (const ev of prop.evidence) {
      const list = quotesByPage.get(ev.page_no) || [];
      list.push(ev.quote);
      quotesByPage.set(ev.page_no, list);
    }
  }

  const missing = decision.coverage?.missing_fields ?? [];
  const warnings = decision.coverage?.warnings ?? [];

  return (
    <article>
      <section className="panel">
        <div className="badge">{decision.regulator_code}</div>
        <div className="badge">{decision.profession}</div>
        <h1 className="brand" style={{ fontSize: "2rem", marginTop: "0.6rem" }}>
          {decision.title}
        </h1>
        <p>{decision.licence_notice}</p>
        <dl className="meta-grid">
          <div>
            <dt>Case reference</dt>
            <dd>{decision.case_ref || "—"}</dd>
          </div>
          <div>
            <dt>Decision date</dt>
            <dd>{decision.decision_date || "—"}</dd>
          </div>
          <div>
            <dt>Practitioner (as published)</dt>
            <dd>{decision.defendant_name_as_published || "—"}</dd>
          </div>
          <div>
            <dt>Registration no.</dt>
            <dd>{decision.defendant_registration_no || "—"}</dd>
          </div>
        </dl>
        {(missing.length > 0 || warnings.length > 0) && (
          <div className="warning">
            <strong>Coverage warnings</strong>
            <ul>
              {missing.map((m) => (
                <li key={m}>Missing field: {m}</li>
              ))}
              {warnings.map((w) => (
                <li key={w}>{w}</li>
              ))}
            </ul>
          </div>
        )}
      </section>

      <section className="panel" style={{ marginTop: "1rem" }}>
        <h2>Published propositions</h2>
        {published.length === 0 && (
          <p className="warning">
            Nothing published yet. Accept items in the review queue.
          </p>
        )}
        <div className="prop-list">
          {published.map((prop) => (
            <div className="prop" key={prop.id} id={`prop-${prop.id}`}>
              <div className="prop-type">
                {prop.prop_type} · {prop.epistemic_class} · conf{" "}
                {prop.confidence.toFixed(2)}
              </div>
              <p className="claim">{prop.claim_text}</p>
              <div className="evidence">
                {prop.evidence.map((ev, idx) => (
                  <div key={`${prop.id}-${idx}`}>
                    <a href={`#page-${ev.page_no}`}>
                      Source: page {ev.page_no}
                      {ev.span_id ? ` · span ${ev.span_id.slice(0, 8)}` : ""}
                    </a>
                    <div style={{ color: "var(--muted)", marginTop: "0.25rem" }}>
                      “{ev.quote}”
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
        {unpublished.length > 0 && (
          <p style={{ marginTop: "1rem", color: "var(--muted)" }}>
            {unpublished.length} proposition(s) awaiting review (hidden from
            search).
          </p>
        )}
      </section>

      <section className="panel" style={{ marginTop: "1rem" }}>
        <h2>Source pages</h2>
        {decision.pages.map((page) => {
          const quotes = quotesByPage.get(page.page_no) || [];
          const html =
            quotes.length > 0
              ? highlightQuote(page.text, quotes[0])
              : escapeHtml(page.text);
          return (
            <div
              className="page-block"
              id={`page-${page.page_no}`}
              key={page.span_id}
            >
              <strong>
                Page {page.page_no}{" "}
                <span className="badge">{page.span_id.slice(0, 8)}</span>
              </strong>
              <pre dangerouslySetInnerHTML={{ __html: html }} />
            </div>
          );
        })}
      </section>
    </article>
  );
}import fs from "node:fs";
import path from "node:path";

export type EvidenceRef = {
  span_id: string | null;
  page_no: number;
  quote: string;
  char_start?: number | null;
  char_end?: number | null;
};

export type Proposition = {
  id: string;
  prop_type: string;
  epistemic_class: string;
  claim_text: string;
  confidence: number;
  review_status: string;
  published: boolean;
  evidence: EvidenceRef[];
};

export type DecisionRecord = {
  id: string;
  document_id: string;
  document_sha256: string;
  regulator_code: string;
  source_id: string;
  title: string;
  case_ref?: string | null;
  decision_date?: string | null;
  profession?: string | null;
  defendant_name_as_published?: string | null;
  defendant_registration_no?: string | null;
  source_url?: string | null;
  licence_notice?: string;
  coverage?: { missing_fields?: string[]; warnings?: string[] };
  pages: Array<{ span_id: string; page_no: number; text: string }>;
  propositions: Proposition[];
  run_key?: string;
};

function unwrap(raw: unknown): DecisionRecord {
  if (
    raw &&
    typeof raw === "object" &&
    "pointer_kind" in (raw as object) &&
    "decision" in (raw as object)
  ) {
    const wrapped = raw as {
      decision: DecisionRecord;
      run_key?: string;
    };
    const decision = { ...wrapped.decision };
    if (!decision.run_key && wrapped.run_key) {
      decision.run_key = wrapped.run_key;
    }
    return decision;
  }
  return raw as DecisionRecord;
}

function roots(): string[] {
  const cwd = process.cwd();
  return [
    path.resolve(cwd, "../../data/seed"),
    path.resolve("/workspace/data/seed"),
    path.resolve(cwd, "../../fixtures/seed"),
    path.resolve("/workspace/fixtures/seed"),
  ];
}

export function loadDecision(id?: string): DecisionRecord | null {
  for (const root of roots()) {
    if (id) {
      const p = path.join(root, "decisions", `${id}.json`);
      if (fs.existsSync(p)) {
        return unwrap(JSON.parse(fs.readFileSync(p, "utf8")));
      }
    } else {
      const fallback = path.join(root, "decision.json");
      if (fs.existsSync(fallback)) {
        return unwrap(JSON.parse(fs.readFileSync(fallback, "utf8")));
      }
    }
  }
  return null;
}

export function listDecisions(): DecisionRecord[] {
  const seen = new Set<string>();
  const out: DecisionRecord[] = [];
  for (const root of roots()) {
    const dir = path.join(root, "decisions");
    if (!fs.existsSync(dir)) continue;
    for (const name of fs.readdirSync(dir)) {
      if (!name.endsWith(".json")) continue;
      const decision = unwrap(
        JSON.parse(fs.readFileSync(path.join(dir, name), "utf8"))
      );
      if (seen.has(decision.id)) continue;
      seen.add(decision.id);
      out.push(decision);
    }
  }
  return out;
}

function writableDecisionPath(id: string): string {
  for (const root of roots()) {
    const p = path.join(root, "decisions", `${id}.json`);
    if (fs.existsSync(p)) return p;
  }
  return path.resolve("/workspace/data/seed/decisions", `${id}.json`);
}

export function saveDecision(decision: DecisionRecord): void {
  const target = writableDecisionPath(decision.id);
  fs.mkdirSync(path.dirname(target), { recursive: true });
  let payload: unknown = decision;
  if (fs.existsSync(target)) {
    const existing = JSON.parse(fs.readFileSync(target, "utf8"));
    if (
      existing &&
      typeof existing === "object" &&
      "pointer_kind" in existing &&
      "decision" in existing
    ) {
      payload = { ...existing, decision, decision_id: decision.id };
    }
  }
  fs.writeFileSync(target, JSON.stringify(payload, null, 2), "utf8");
  const root = path.dirname(path.dirname(target));
  fs.writeFileSync(
    path.join(root, "decision.json"),
    JSON.stringify(payload, null, 2),
    "utf8"
  );
}

export function canPublish(review_status: string, evidence: unknown[]): boolean {
  if (review_status !== "accepted" && review_status !== "edited") return false;
  return Array.isArray(evidence) && evidence.length > 0;
