import { listDecisions, loadDecision } from "../lib/data";

export default function HomePage() {
  const decision = loadDecision();
  const decisions = listDecisions();
  const pending = decisions.reduce(
    (n, d) =>
      n +
      d.propositions.filter(
        (p) => !p.published && p.review_status !== "rejected"
      ).length,
    0
  );
  const published = decisions.reduce(
    (n, d) => n + d.propositions.filter((p) => p.published).length,
    0
  );

  return (
    <section className="panel">
      <h1>RegLens HK</h1>
      <p>
        Milestone 2A contracts on the MVP backbone: immutable extraction runs,
        synthetic fixtures, human review, publication gate, and keyword FTS.
        Semantic search and live crawling are disabled.
      </p>
      <dl className="meta-grid">
        <div>
          <dt>Decisions</dt>
          <dd>{decisions.length}</dd>
        </div>
        <div>
          <dt>Published propositions</dt>
          <dd>{published}</dd>
        </div>
        <div>
          <dt>Review queue</dt>
          <dd>{pending}</dd>
        </div>
      </dl>
      <p>
        <Link href="/search">Search published propositions</Link>
        {" · "}
        <Link href="/review">Open review queue</Link>
      </p>
      {decision ? (
        <p>
          <Link href={`/decisions/${decision.id}`}>
            Open {decision.title || decision.case_ref || decision.id}
          </Link>
        </p>
      ) : (
        <p className="warning">
          No seed found. Run{" "}
          <code>
            python -m reglens_worker ingest --manifest
            fixtures/manifests/m1.jsonl --demo-auto-approve-synthetic
          </code>{" "}
          from the repo root (with <code>PYTHONPATH=services/worker</code>).
        </p>
      )}
    </section>
  );
}# System architecture (Milestone 2A)

```mermaid
flowchart TB
  Fixtures[Synthetic fixtures and manifest]
  Ingest[Ingest hash segment]
  Extract[Mock LLM provider v2]
  Val[JSON Schema and domain invariants]
  Runs[Immutable run store meta/runs/run_key]
  Pointer[Mutable demo pointer seed]
  Web[Next.js decision page]

  Fixtures --> Ingest --> Extract --> Val --> Runs
  Runs --> Pointer --> Web
```

## Milestone 2A focus

Trusted contracts, deterministic immutable artifacts, synthetic/private-data boundary, and CI.
PostgreSQL persistence, MinIO wiring, authentication, review UI, and search are **out of scope** for 2A (see Milestone 2B+).

## Design notes

- Documents are untrusted data.
- Mock provider only; no network LLM calls.
- Atomic writes; run-key conflicts quarantine differing outputs.
- Compose file remains for local infra prep; image tags are pinned; credentials labelled local-only.# Extraction JSON Schema

## Current contract (v2)

Source of truth: [`packages/extraction-schema/extraction_result.v2.json`](../packages/extraction-schema/extraction_result.v2.json).

| Rule | Detail |
|------|--------|
| Version | `schema_version` = `2.0.0` |
| Identity | Providers emit `client_ref` only — **no** database UUIDs |
| Required | `decision_metadata`, `coverage`, `propositions` |
| Case refs | `decision_metadata.case_refs` array |
| Dates | typed: inquiry, judgment, publication, conduct, order_effective (`format: date`) |
| Derivation | `verbatim` \| `normalized` \| `inferred` |
| Epistemic | `fact` \| `interpretation` (`legal_test` ⇒ interpretation) |
| Relations | by `client_ref` (finding_resolves_charge, sanction_applies_to_charge, rule_governs_charge, authority_supports_legal_test, factor_affects_sanction) |
| Evidence | `page_no` + `quote`; `span_id` required after resolution; offsets only as a pair with `char_end >= char_start` |
| Additional properties | rejected |

## Domain invariants

Implemented in `reglens_worker.schema_validate.domain_validate_extraction` with an explicit JSON Schema `FormatChecker` for dates.

## Migration from v1

`migrate_v1_to_v2()` maps `case_ref`/`decision_date`/`id` → `case_refs`/`dates.judgment`/`client_ref`. v1 schema file is retained for validation of legacy fixtures.

## Post-validation

Missing or mismatched evidence fails validation — the mock provider does **not** substitute the first line of a page.# Local setup — Milestone 2A

## Baseline restrictions

Internal/non-commercial; no crawl; no real LLM; no OCR; no semantic search; no NCHK;
no real documents in Git.

## Python

```bash
python3 -m venv .venv
source .venv/bin/activate
pip install -r services/worker/requirements.txt
# optional lock refresh: make lock
export PYTHONPATH=services/worker
```

## Ingest (default: pending / unpublished)

```bash
python -m reglens_worker ingest --manifest fixtures/manifests/m1.jsonl --data-root data
```

Synthetic demo auto-approve (rejects non-synthetic rows):

```bash
python -m reglens_worker ingest --manifest fixtures/manifests/m1.jsonl --data-root data --demo-auto-approve-synthetic
```

Immutable audit artifacts: `data/meta/runs/<run_key>/extraction.json` (+ `.sha256`).
Demo pointer only: `data/seed/decision.json`.

## Verify everything

```bash
make verify
```

## Web

```bash
cd apps/web
npm ci
npm run typecheck
npm run build
npm run dev
```

## Private data

See `docs/PRIVATE_DATA.md`. The `private-data/` tree is gitignored.

## Compose (optional; local-only credentials)

```bash
docker compose config   # validate file
docker compose up -d db minio
```# Phase 0 planning package — index

