  meta/documents/<sha>.json
  meta/spans/<sha>.json
  meta/runs/<run_key>/
    extraction.json                # immutable
    extraction.sha256
    decision.json                  # immutable pending decision view
    quarantine/                    # conflicting outputs if any
  seed/decision.json               # mutable synthetic demo pointer only
```

